// Search issues an Expensify /Search call with a typed filter tree and parses
// the response envelope. On a non-200 jsonCode, returns a *expensifysearch.SearchError
// so command handlers can classify auth vs API errors without parsing strings.
//
// The on-the-wire shape is:
//
//	POST /Search
//	    jsonQuery=<marshaled Query>
//	    hash=<q.Hash as string>   (omitted when zero)
//
// The existing form-body flow in buildNewExpensifyRequest flattens these fields
// alongside authToken/platform/referer — no new routing is introduced.
func (c *Client) Search(q expensifysearch.Query) (*expensifysearch.Response, error) {
	jq, err := json.Marshal(q)
	if err != nil {
		return nil, fmt.Errorf("marshaling Search query: %w", err)
	}
	body := map[string]any{
		"jsonQuery": string(jq),
	}
	if q.Hash != 0 {
		body["hash"] = strconv.Itoa(q.Hash)
	}

	raw, _, err := c.Post("/Search", body)
	if err != nil {
		return nil, err
	}

	var resp expensifysearch.Response
	if err := json.Unmarshal(raw, &resp); err != nil {
		return nil, fmt.Errorf("parsing /Search response: %w", err)
	}
	if resp.JSONCode != 0 && resp.JSONCode != 200 {
		return &resp, &expensifysearch.SearchError{
			JSONCode: resp.JSONCode,
			Message:  resp.Message,
			Query:    q,
		}
	}
	return &resp, nil
}

// do executes an HTTP request. headerOverrides, when non-nil, override global
// RequiredHeaders for this specific request (used for per-endpoint API versioning).
//
// Expensify-specific protocol:
//   - Paths starting with /Integration-Server/ use the Integration Server dispatcher:
//     form-encoded body with a single "requestJobDescription" field whose value is a
//     JSON document containing credentials and inputSettings.
//   - All other paths target www.expensify.com/api and use form-encoded bodies with
//     authToken + every body field as form fields. No Authorization header.
func (c *Client) do(method, path string, params map[string]string, body any, headerOverrides map[string]string) (json.RawMessage, int, error) {
	targetURL, bodyBytes, contentType, err := c.buildExpensifyRequest(method, path, body)
	if err != nil {
		return nil, 0, err
	}

	// Auth header is not used for Expensify (auth is in body) but the dry-run
	// preview still wants to show "no Authorization header"; pass empty string.
	authHeader := ""

	// Build the request for dry-run display or actual execution
	if c.DryRun {
		return c.dryRun(method, targetURL, path, params, bodyBytes, headerOverrides, authHeader)
	}
	_ = contentType // used via bodyContentType below

	const maxRetries = 3
	var lastErr error

	for attempt := 0; attempt <= maxRetries; attempt++ {
		// Proactive rate limiting — wait before sending
		c.limiter.Wait()
		var bodyReader io.Reader
		if bodyBytes != nil {
			bodyReader = strings.NewReader(string(bodyBytes))
		}

		req, err := http.NewRequest(method, targetURL, bodyReader)
		if err != nil {
			return nil, 0, fmt.Errorf("creating request: %w", err)
		}
		if bodyBytes != nil {
			req.Header.Set("Content-Type", contentType)
		}

		if params != nil {
			q := req.URL.Query()
			for k, v := range params {
				if v != "" {
					q.Set(k, v)
				}
			}
			req.URL.RawQuery = q.Encode()
		}

		// Per-endpoint header overrides (e.g., different API version per resource)
		for k, v := range headerOverrides {
			req.Header.Set(k, v)
		}
		req.Header.Set("User-Agent", "expensify-pp-cli/0.1.0")

		resp, err := c.HTTPClient.Do(req)
		if err != nil {
			lastErr = fmt.Errorf("%s %s: %w", method, path, err)
			continue
		}

		respBody, err := io.ReadAll(resp.Body)
		resp.Body.Close()
		if err != nil {
			return nil, 0, fmt.Errorf("reading response: %w", err)
		}
		respBody = sanitizeJSONResponse(respBody)

		// Success
		if resp.StatusCode < 400 {
			c.limiter.OnSuccess()
			return json.RawMessage(respBody), resp.StatusCode, nil
		}

		apiErr := &APIError{
			Method:     method,
			Path:       path,
			StatusCode: resp.StatusCode,
			Body:       truncateBody(respBody),
		}

		// Rate limited - adjust adaptive limiter and retry
		if resp.StatusCode == 429 && attempt < maxRetries {
			c.limiter.OnRateLimit()
			wait := retryAfter(resp)
			fmt.Fprintf(os.Stderr, "rate limited, waiting %s (attempt %d/%d, rate adjusted to %.1f req/s)\n", wait, attempt+1, maxRetries, c.limiter.Rate())
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Server error - retry with backoff
		if resp.StatusCode >= 500 && attempt < maxRetries {
			wait := time.Duration(math.Pow(2, float64(attempt))) * time.Second
			fmt.Fprintf(os.Stderr, "server error %d, retrying in %s (attempt %d/%d)\n", resp.StatusCode, wait, attempt+1, maxRetries)
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Client error or retries exhausted - return the error
		return nil, resp.StatusCode, apiErr
	}

	return nil, 0, lastErr
}

// dryRun prints the outgoing request exactly as the live path would send it,
// using the auth material already resolved in `do()`. Never triggers a network
// call — the caller is responsible for passing cached auth material only.
func (c *Client) dryRun(method, targetURL, path string, params map[string]string, body []byte, headerOverrides map[string]string, authHeader string) (json.RawMessage, int, error) {
	fmt.Fprintf(os.Stderr, "%s %s\n", method, targetURL)
	if params != nil {
		for k, v := range params {
			if v != "" {
				fmt.Fprintf(os.Stderr, "  ?%s=%s\n", k, v)
			}
		}
	}
	if body != nil {
		var pretty json.RawMessage
		if json.Unmarshal(body, &pretty) == nil {
			enc := json.NewEncoder(os.Stderr)
			enc.SetIndent("  ", "  ")
			fmt.Fprintf(os.Stderr, "  Body:\n")
			enc.Encode(pretty)
		}
	}
	if authHeader != "" {
		fmt.Fprintf(os.Stderr, "  %s: %s\n", "Authorization", maskToken(authHeader))
	}
	fmt.Fprintf(os.Stderr, "\n(dry run - no request sent)\n")
	return json.RawMessage(`{"dry_run": true}`), 0, nil
}

func (c *Client) authHeader() (string, error) {
	if c.Config == nil {
		return "", nil
	}
	if c.Config.AccessToken != "" && !c.Config.TokenExpiry.IsZero() && time.Now().After(c.Config.TokenExpiry) && c.Config.RefreshToken != "" {
		if err := c.refreshAccessToken(); err != nil {
			return "", err
		}
	}
	return c.Config.AuthHeader(), nil
}

func (c *Client) refreshAccessToken() error {
	if c.Config == nil {
		return nil
	}
	if c.Config.RefreshToken == "" {
		return nil
	}

	tokenURL := ""
	if tokenURL == "" {
		return nil
	}

	params := url.Values{
		"grant_type":    {"refresh_token"},
		"refresh_token": {c.Config.RefreshToken},
		"client_id":     {c.Config.ClientID},
	}
	if c.Config.ClientSecret != "" {
		params.Set("client_secret", c.Config.ClientSecret)
	}

	resp, err := c.HTTPClient.PostForm(tokenURL, params)
	if err != nil {
		return fmt.Errorf("refreshing access token: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		body, _ := io.ReadAll(resp.Body)
		return fmt.Errorf("refreshing access token: HTTP %d: %s", resp.StatusCode, truncateBody(body))
	}

	var tokenResp struct {
		AccessToken  string `json:"access_token"`
		RefreshToken string `json:"refresh_token"`
		ExpiresIn    int    `json:"expires_in"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&tokenResp); err != nil {
		return fmt.Errorf("parsing refresh response: %w", err)
	}
	if tokenResp.AccessToken == "" {
		return fmt.Errorf("refreshing access token: no access token in response")
	}

	refreshToken := c.Config.RefreshToken
	if tokenResp.RefreshToken != "" {
		refreshToken = tokenResp.RefreshToken
	}

	expiry := time.Time{}
	if tokenResp.ExpiresIn > 0 {
		expiry = time.Now().Add(time.Duration(tokenResp.ExpiresIn) * time.Second)
	}

	if err := c.Config.SaveTokens(c.Config.ClientID, c.Config.ClientSecret, tokenResp.AccessToken, refreshToken, expiry); err != nil {
		return fmt.Errorf("saving refreshed token: %w", err)
	}

	return nil
}

const maxRetryWait = 60 * time.Second

func retryAfter(resp *http.Response) time.Duration {
	header := resp.Header.Get("Retry-After")
	if header == "" {
		return 5 * time.Second
	}
	if seconds, err := strconv.Atoi(header); err == nil {
		d := time.Duration(seconds) * time.Second
		if d > maxRetryWait {
			return maxRetryWait
		}
		return d
	}
	if t, err := http.ParseTime(header); err == nil {
		wait := time.Until(t)
		if wait > maxRetryWait {
			return maxRetryWait
		}
		if wait > 0 {
			return wait
		}
	}
	return 5 * time.Second
}

// sanitizeJSONResponse strips known JSONP/XSSI prefixes and UTF-8 BOM from
// response bodies so that downstream JSON parsing succeeds. For clean JSON
// responses these checks are no-ops.
func sanitizeJSONResponse(body []byte) []byte {
	// UTF-8 BOM
	body = bytes.TrimPrefix(body, []byte("\xEF\xBB\xBF"))

	// JSONP/XSSI prefixes, ordered longest-first where prefixes overlap
	prefixes := [][]byte{
		[]byte(")]}'\n"),
		[]byte(")]}'"),
		[]byte("{}&&"),
		[]byte("for(;;);"),
		[]byte("while(1);"),
	}
	for _, p := range prefixes {
		if bytes.HasPrefix(body, p) {
			body = bytes.TrimPrefix(body, p)
			body = bytes.TrimLeft(body, " \t\r\n")
			break
		}
	}
	return body
}

// maskToken redacts all but the last 4 characters of a token for safe display.
func maskToken(token string) string {
	if token == "" {
		return ""
	}
	if len(token) <= 4 {
		return "****"
	}
	return "****" + token[len(token)-4:]
}

func truncateBody(b []byte) string {
	s := string(b)
	if len(s) > 200 {
		return s[:200] + "..."
	}
	return s
}

// buildExpensifyRequest constructs the URL, body bytes, and content-type for an
// Expensify API request. Expensify does NOT follow REST conventions — instead,
// it has two dispatcher endpoints, each with their own body shape:
//
//  1. New Expensify (www.expensify.com/api/<Command>): POST with form-encoded
//     body containing authToken + every body field flattened into form fields.
//     Nested objects are JSON-encoded as a single string field.
//
//  2. Integration Server (integrations.expensify.com/Integration-Server/...):
//     POST with form-encoded body containing a single "requestJobDescription"
//     field whose value is a JSON document with credentials, inputSettings,
//     and optionally onReceive/onFinish actions.
//
// This function picks the right shape based on the path prefix.
func (c *Client) buildExpensifyRequest(method, path string, body any) (string, []byte, string, error) {
	// Route: Integration Server vs New Expensify
	if strings.HasPrefix(path, "/Integration-Server/") {
		return c.buildIntegrationServerRequest(method, path, body)
	}
	return c.buildNewExpensifyRequest(method, path, body)
}

func (c *Client) buildNewExpensifyRequest(method, path string, body any) (string, []byte, string, error) {
	targetURL := "https://www.expensify.com/api" + path
	if c.Config != nil && c.Config.BaseURL != "" && !strings.Contains(c.Config.BaseURL, "www.expensify.com/api") {
		// Allow BaseURL override for tests / verify's mock server
		targetURL = c.Config.BaseURL + path
	}

	form := url.Values{}
	// authToken: required for every New Expensify command. Skip if not set so
	// dry-run still works and unauthenticated errors are surfaced from the
	// server's response rather than an early client-side abort.
	if c.Config != nil && c.Config.ExpensifyAuthToken != "" {
		form.Set("authToken", c.Config.ExpensifyAuthToken)
	}
	// Standard parameters every /api call includes in practice. Expensify
	// validates `referer` against a known app-name allowlist — `expensify-pp-cli`
	// gets rejected with jsonCode 666, so we mimic the web app's referer ("ecash")
	// which is what ReconnectApp / Search / the command dispatcher expect.
	form.Set("platform", "web")
	form.Set("referer", "ecash")
	form.Set("api_setCookie", "false")

	// Flatten body into form fields. Strings/numbers/bools go directly; maps
	// and slices are JSON-encoded into a single string field.
	if body != nil {
		if m, ok := body.(map[string]any); ok {
			for k, v := range m {
				if v == nil {
					continue
				}
				switch x := v.(type) {
				case string:
					if x != "" {
						form.Set(k, x)
					}
				case bool:
					form.Set(k, strconv.FormatBool(x))
				case int:
					form.Set(k, strconv.Itoa(x))
				case int64:
					form.Set(k, strconv.FormatInt(x, 10))
				case float64:
					form.Set(k, strconv.FormatFloat(x, 'f', -1, 64))
				default:
					if jb, err := json.Marshal(v); err == nil {
						form.Set(k, string(jb))
					}
				}
			}
		} else {
			// Non-map body: JSON-encode under "body" key
			if jb, err := json.Marshal(body); err == nil {
				form.Set("body", string(jb))
			}
		}
	}

	return targetURL, []byte(form.Encode()), "application/x-www-form-urlencoded", nil
}

func (c *Client) buildIntegrationServerRequest(method, path string, body any) (string, []byte, string, error) {
	targetURL := "https://integrations.expensify.com" + path
	if c.Config != nil && c.Config.BaseURL != "" && strings.Contains(c.Config.BaseURL, "integrations.expensify.com") {
		targetURL = c.Config.BaseURL + strings.TrimPrefix(path, "/Integration-Server")
	}

	// Build the requestJobDescription JSON wrapper
	wrapper := map[string]any{}
	if c.Config != nil {
		wrapper["credentials"] = map[string]string{
			"partnerUserID":     c.Config.ExpensifyPartnerUserId,
			"partnerUserSecret": c.Config.ExpensifyPartnerUserSecret,
		}
	}

	if m, ok := body.(map[string]any); ok {
		// Expensify Integration Server expects:
		//   { type, inputSettings: {...}, credentials, onReceive, onFinish }
		// The command body already carries type + the right nested fields in its
		// own conventions; we pass everything through under inputSettings unless
		// the body already has "type".
		if _, hasType := m["type"]; !hasType {
			// Default type inference from the command name in path is brittle;
			// require the caller to set "type" for Integration Server commands.
			// Without type, just pass-through for now — let the server report the error.
		}
		for k, v := range m {
			wrapper[k] = v
		}
	}

	jb, err := json.Marshal(wrapper)
	if err != nil {
		return "", nil, "", fmt.Errorf("marshaling requestJobDescription: %w", err)
	}
	form := url.Values{}
	form.Set("requestJobDescription", string(jb))
	return targetURL, []byte(form.Encode()), "application/x-www-form-urlencoded", nil
}
